[web]
{
parm(in:&Mode, in:&EmpCod, in:&LctCod);

EmpCod = &EmpCod if not &EmpCod.IsEmpty();
noaccept(EmpCod) if not &EmpCod.IsEmpty();
LctCod = &LctCod if not &LctCod.IsEmpty();
noaccept(LctCod) if not &LctCod.IsEmpty();Default(EmpCod, &EmpCodInitialValue);
Default(LctCod, &LctCodInitialValue);
Default(LctNom, &LctNomInitialValue);
Default(LctCodNom, &LctCodNomInitialValue);
Default(LctNatOpe, &LctNatOpeInitialValue);
Default(LctTip, &LctTipInitialValue);
Default(LctGerFin, &LctGerFinInitialValue);
Default(LctPagCom, &LctPagComInitialValue);
Default(LctInfPrc, &LctInfPrcInitialValue);
Default(LctTipCus, &LctTipCusInitialValue);
Default(LctRetCus, &LctRetCusInitialValue);
Default(LctAtuFor, &LctAtuForInitialValue);
Default(LctBasImpCod, &LctBasImpCodInitialValue);
Default(LctAtuSal, &LctAtuSalInitialValue);
Default(LctAtuEst, &LctAtuEstInitialValue);
Default(LctAtuPro, &LctAtuProInitialValue);
Default(LctAtuEstFis, &LctAtuEstFisInitialValue);
Default(LctPerCred, &LctPerCredInitialValue);
Default(LctGnre, &LctGnreInitialValue);
Default(LctCalMin, &LctCalMinInitialValue);
Default(LctEmsCot, &LctEmsCotInitialValue);
Default(LctDesFun, &LctDesFunInitialValue);
Default(LctIncFun, &LctIncFunInitialValue);
Default(LctDesSen, &LctDesSenInitialValue);
Default(LctIncSen, &LctIncSenInitialValue);
Default(LctCodCta, &LctCodCtaInitialValue);
Default(LctUntArr, &LctUntArrInitialValue);
Default(LctStsCod, &LctStsCodInitialValue);
Default(LctAtuGra, &LctAtuGraInitialValue);
Default(LctObsPad, &LctObsPadInitialValue);
Default(LctTabColCod, &LctTabColCodInitialValue);
Default(LctInfAnoSafCul, &LctInfAnoSafCulInitialValue);
Default(LctCha, &LctChaInitialValue);
Default(LctCrt, &LctCrtInitialValue);
Default(LctModPad, &LctModPadInitialValue);
Default(LctAprvICMS, &LctAprvICMSInitialValue);
Default(LctMovImo, &LctMovImoInitialValue);
Default(LctAprvIPI, &LctAprvIPIInitialValue);
Default(LctIcmsRet, &LctIcmsRetInitialValue);
Default(LctCodCtaM410, &LctCodCtaM410InitialValue);
Default(LctCodCtaRFB, &LctCodCtaRFBInitialValue);
Default(LctNfeIndPres, &LctNfeIndPresInitialValue);
Default(LctPadPisCof, &LctPadPisCofInitialValue);
Default(LctCodNatCrdPisCof, &LctCodNatCrdPisCofInitialValue);
Default(LctClsCST, &LctClsCSTInitialValue);
Default(LctClsTrib, &LctClsTribInitialValue);
Default(LctClsTribFix, &LctClsTribFixInitialValue);
Default(LctFin, &LctFinInitialValue);
Default(LctFinDeb, &LctFinDebInitialValue);
Default(LctFinCred, &LctFinCredInitialValue);
Default(LctDscMaxLib, &LctDscMaxLibInitialValue);

}

Error(Format('WWP_RequiredAttribute','Lançamento Pagar/Descontar Comissão')) if LctPagCom.IsEmpty();
Error(Format('WWP_RequiredAttribute','Digitar Valor Pedido')) if LctInfPrc.IsEmpty();
Error(Format('WWP_RequiredAttribute','Lançamento Gera Financeiro')) if LctGerFin.IsEmpty();
Error(Format('WWP_RequiredAttribute','Lançamento Nome')) if LctNom.IsEmpty();
Error(Format('WWP_RequiredAttribute','Lançamento Natureza Operação')) if LctNatOpe.IsEmpty();
Error(Format('WWP_RequiredAttribute','Lançamento Tipo')) if LctTip.IsEmpty();
Default(EmpCod,&Context.EmpCod);
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

Default(EmpCod, &Context.EmpCod);

prcTipoLancamentoCodigo.Call(&Context.EmpCod, LctCod) If insert and LctCod.IsEmpty() on AfterValidate;

[web]
{
	LctBasImpCod = LctCod If LctBasImpCod.IsEmpty() on AfterValidate;	

	prompt(promptSpedNatureza, EmpCod, LctCodCta);
	prompt(PromptModeloDocumentos, LctModPad);

	prompt(PromptClassificacaoTributaria, LctClsCST);
	prompt(PromptClassificacaoTributariaCltCls, LctClsCST, LctClsTrib);

	LctCalMin.Visible = (LctTip <> TipoLancamento.EntradaMercadoria or LctTip = TipoLancamento.DevolucaoCompra and LctTip = TipoLancamento.OrcamentoCompra);
	LctTipCus.Visible = (LctTip = TipoLancamento.EntradaMercadoria or  LctTip =  TipoLancamento.OrcamentoCompra);
	LctRetCus.Visible = (LctTip = TipoLancamento.SaidaMercadoria or LctTip = TipoLancamento.DevolucaoCompra or LctTip = TipoLancamento.OrcamentoVenda);
	LctAtuFor.Visible = (LctTip = TipoLancamento.EntradaMercadoria  or LctTip =  TipoLancamento.OrcamentoCompra);	
	tbRetido.Visible = (LctTip = TipoLancamento.EntradaMercadoria  or LctTip =  TipoLancamento.OrcamentoCompra); //COMPRA
	tbGnre.Visible = (LctTip = TipoLancamento.SaidaMercadoria or LctTip = TipoLancamento.OrcamentoVenda); //VENDA
}

//JDF COMENTEI PORQUE NAO RESOLVEU.
//LctNatOpe = LctNom if after(LctNom) and LctNatOpe.IsEmpty();
//LctAtuEstFis = LctAtuEst if LctAtuEstFis.IsNull() or LctAtuEstFis.IsEmpty();


&ModNom = RetornaNomeModeloDocumentoFiscal.Udp(LctModPad) if after(LctModPad);

Event Start
LoadWWPContext.Call(&Context) If &Mode = TrnMode.Delete retornaAutorizacao.Call('WWTIPOLANCAMENTO', Status_SimNao.Sim, 3, &AutNiv) Else retornaAutorizacao.Call('WWTIPOLANCAMENTO', Status_SimNao.Sim, 2, &AutNiv) EndIF
RetornaEmpresaModulo.Call(&Context.EmpCod, moduloSistema.AGRO_INSUMOS, &AGRO_INSUMOS ) [web] { tbAgroInsumos.Visible = &AGRO_INSUMOS = 'S' } &PossuiModuloGoverno = RetornaEmpresaModulo.UDP(&Context.EmpCod, ModuloSistema.GOVERNO)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
[web] { LctInfPrc.TooltipText = "'SIM' - Para Habilitar o campo unitário nos pedidos de Compra/Venda" LctPagCom.TooltipText = '"SIM" - Caso deseja utilizar para no cálculo de Comissões' LctGerFin.TooltipText = '"SIM" - Para gerar contas à Pagar/Receber' LctAtuFor.TooltipText = 'Atualiza o "Produtos X Fornecedor" com valores e taxas informados no pedido de compra. Regra valida apenas Pedido de compra.' LctRetCus.TooltipText = "Retorna o custo ao pedido de venda. Ex: Venda a Funcionario" LctCalMin.TooltipText = "Utilizar esse tipo de lançamento para cálculo de Estoque Mínimo." LctPerCred.TooltipText = "Operação permite aproveitar crédito ICMS" LctBasImpCod.TooltipText = 'Código de Lançamento de onde será pego as configurações dos impostos. "0" para pegar do código cadastrado agora.' UnnamedTable24.Width = 200 UnnamedTable23.Width = 150 LctNatOpe.TooltipText = "Campo discritivo utilizado para sair impresso na nota." LctCod.TooltipText = "Sequência manual, precisa localizar um número não utilizado" }
[web] { EmpCod.Visible = False LctAtuSal.Visible = False If &Mode = TrnMode.Insert &TipoLancamentoCopyRecordXml = &WebSession.Get(!'TipoLancamentoCopyRecord') If &TipoLancamentoCopyRecordXml.Trim() <> '' &TipoLancamentoCopyRecord.FromXml(&TipoLancamentoCopyRecordXml) &WebSession.Remove(!'TipoLancamentoCopyRecord') &EmpCodInitialValue = &TipoLancamentoCopyRecord.EmpCod &LctCodInitialValue = &TipoLancamentoCopyRecord.LctCod &LctNomInitialValue = &TipoLancamentoCopyRecord.LctNom &LctCodNomInitialValue = &TipoLancamentoCopyRecord.LctCodNom &LctNatOpeInitialValue = &TipoLancamentoCopyRecord.LctNatOpe &LctTipInitialValue = &TipoLancamentoCopyRecord.LctTip &LctGerFinInitialValue = &TipoLancamentoCopyRecord.LctGerFin &LctPagComInitialValue = &TipoLancamentoCopyRecord.LctPagCom &LctInfPrcInitialValue = &TipoLancamentoCopyRecord.LctInfPrc &LctTipCusInitialValue = &TipoLancamentoCopyRecord.LctTipCus &LctRetCusInitialValue = &TipoLancamentoCopyRecord.LctRetCus &LctAtuForInitialValue = &TipoLancamentoCopyRecord.LctAtuFor &LctBasImpCodInitialValue = &TipoLancamentoCopyRecord.LctBasImpCod &LctAtuSalInitialValue = &TipoLancamentoCopyRecord.LctAtuSal &LctAtuEstInitialValue = &TipoLancamentoCopyRecord.LctAtuEst &LctAtuProInitialValue = &TipoLancamentoCopyRecord.LctAtuPro &LctAtuEstFisInitialValue = &TipoLancamentoCopyRecord.LctAtuEstFis &LctPerCredInitialValue = &TipoLancamentoCopyRecord.LctPerCred &LctGnreInitialValue = &TipoLancamentoCopyRecord.LctGnre &LctCalMinInitialValue = &TipoLancamentoCopyRecord.LctCalMin &LctEmsCotInitialValue = &TipoLancamentoCopyRecord.LctEmsCot &LctDesFunInitialValue = &TipoLancamentoCopyRecord.LctDesFun &LctIncFunInitialValue = &TipoLancamentoCopyRecord.LctIncFun &LctDesSenInitialValue = &TipoLancamentoCopyRecord.LctDesSen &LctIncSenInitialValue = &TipoLancamentoCopyRecord.LctIncSen &LctCodCtaInitialValue = &TipoLancamentoCopyRecord.LctCodCta &LctUntArrInitialValue = &TipoLancamentoCopyRecord.LctUntArr &LctStsCodInitialValue = &TipoLancamentoCopyRecord.LctStsCod &LctAtuGraInitialValue = &TipoLancamentoCopyRecord.LctAtuGra &LctObsPadInitialValue = &TipoLancamentoCopyRecord.LctObsPad &LctTabColCodInitialValue = &TipoLancamentoCopyRecord.LctTabColCod &LctInfAnoSafCulInitialValue = &TipoLancamentoCopyRecord.LctInfAnoSafCul &LctChaInitialValue = &TipoLancamentoCopyRecord.LctCha &LctCrtInitialValue = &TipoLancamentoCopyRecord.LctCrt &LctModPadInitialValue = &TipoLancamentoCopyRecord.LctModPad &LctAprvICMSInitialValue = &TipoLancamentoCopyRecord.LctAprvICMS &LctMovImoInitialValue = &TipoLancamentoCopyRecord.LctMovImo &LctAprvIPIInitialValue = &TipoLancamentoCopyRecord.LctAprvIPI &LctIcmsRetInitialValue = &TipoLancamentoCopyRecord.LctIcmsRet &LctCodCtaM410InitialValue = &TipoLancamentoCopyRecord.LctCodCtaM410 &LctCodCtaRFBInitialValue = &TipoLancamentoCopyRecord.LctCodCtaRFB &LctNfeIndPresInitialValue = &TipoLancamentoCopyRecord.LctNfeIndPres &LctPadPisCofInitialValue = &TipoLancamentoCopyRecord.LctPadPisCof &LctCodNatCrdPisCofInitialValue = &TipoLancamentoCopyRecord.LctCodNatCrdPisCof &LctClsCSTInitialValue = &TipoLancamentoCopyRecord.LctClsCST &LctClsTribInitialValue = &TipoLancamentoCopyRecord.LctClsTrib &LctClsTribFixInitialValue = &TipoLancamentoCopyRecord.LctClsTribFix &LctFinInitialValue = &TipoLancamentoCopyRecord.LctFin &LctFinDebInitialValue = &TipoLancamentoCopyRecord.LctFinDeb &LctFinCredInitialValue = &TipoLancamentoCopyRecord.LctFinCred &LctDscMaxLibInitialValue = &TipoLancamentoCopyRecord.LctDscMaxLib EndIf EndIf }
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
if &TipoLancamentoCopyRecordXml.Trim() = '' &EmpCodInitialValue = &Context.EmpCod &LctAtuEstInitialValue = Status_entradaSaida.Nenhum &LctAtuEstFisInitialValue = Status_entradaSaida.Nenhum &LctAtuProInitialValue = Status_entradaSaida.Nenhum &LctAtuGraInitialValue = Status_SimNao_PS.Nao &LctAprvICMSInitialValue = 100 &LctAprvIPIInitialValue = 100 Else &LctCodInitialValue.SetEmpty()
if &LctAtuEstFisInitialValue.IsEmpty() &LctAtuEstFisInitialValue = &LctAtuEstInitialValue Endif
Endif
do 'AttributesSecurityCode'
//GRAVAR LOG &LogErpTabIsLog = prcGetIsGravarLog.Udp(&Context.EmpCod, 'TIPOLANCAMENTO') if &LogErpTabIsLog = true //SE GRAVAR CARREGA ARQUIVOS &LogErpRegTip = iif(&Mode = TrnMode.Delete, TrnMode.Delete, iif(&LctCod = 0, Trnmode.Insert, Trnmode.Update)) prcCarregaLog_TipoLancamento.Call(&EmpCod, &LctCod, &SdtLogAtributos) Endif
EndEvent
Event After Trn
If &Mode <> TrnMode.Delete atualizaFormulasOperacao.Call(EmpCod, LctCod) EndIf
if &LogErpTabIsLog = true //GRAVA LOG prcGravaLog_TipoLancamento.Call(&LogErpRegTip, &Context.EmpCod, &Context.FilCod, LctCod, &Pgmname, &Context.UserName, &SdtLogAtributos) Endif
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
[web] {
Return }
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event LctTip.IsValid
Do 'AttributesSecurityCode'
EndEvent
Sub 'AttributesSecurityCode'
[web] { TableGoverno.Visible = (&PossuiModuloGoverno = 'S') }
EndSub
